#version 330 core
in vec2 v_uv;out vec4 fragColor;uniform float u_time;
uniform float u_scale;  // spatial scale  (3.0)
uniform float u_speed;  // time scale     (1.0)
void main(){vec2 uv=v_uv*u_scale;float t=u_time*u_speed;
  float v=sin(uv.x+t)+sin(uv.y+t*.7)+sin(uv.x+uv.y+t*.5)+sin(length(uv-u_scale*.5)+t*1.3);
  fragColor=vec4(.5+.5*sin(v*3.14159+vec3(0.,2.094,4.189)),1.);}

#version 330 core
in vec2 v_uv;out vec4 fragColor;uniform sampler2D iChannel0;
uniform float u_cycles;  // palette cycles  (1.0)
uniform float u_shift;   // hue shift       (0.0)
uniform float u_sat;     // saturation      (1.0)
uniform float u_lum;     // luma blend      (0.0)
void main(){vec3 src=texture(iChannel0,v_uv).rgb;
  float luma=dot(src,vec3(.299,.587,.114));
  float h=fract(luma*u_cycles+u_shift);
  vec4 K=vec4(1.,2./3.,1./3.,3.);vec3 f=abs(fract(h+K.xyz)*6.-K.www);
  vec3 col=mix(K.xxx,clamp(f-K.xxx,0.,1.),u_sat);
  fragColor=vec4(mix(col,vec3(luma),u_lum),1.);}
